package com.chaobo.scm.supplier.application.returning;
import com.chaobo.scm.common.error.*;import com.chaobo.scm.supplier.application.integration.InboundEventPayloadStore;import com.chaobo.scm.supplier.application.masterdata.MasterDataEventConsumeLogPort;import com.chaobo.scm.supplier.application.shared.CommandContext;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import java.util.Set;
@Service public class SupplierReturnEventConsumerApplicationService{private static final String CONSUMER="supplier-return";private final MasterDataEventConsumeLogPort inbox;private final SupplierReturnApplicationService returns;private final InboundEventPayloadStore payloads;public SupplierReturnEventConsumerApplicationService(MasterDataEventConsumeLogPort inbox,SupplierReturnApplicationService returns,InboundEventPayloadStore payloads){this.inbox=inbox;this.returns=returns;this.payloads=payloads;}@Transactional public void consume(SupplierReturnExternalEvent event){if(!Set.of("INVENTORY","WMS","TMS","BMS").contains(event.sourceSystem()))throw new BusinessException(ErrorCode.BUSINESS_RULE_FAILED,"退供事件来源不合法");var claim=inbox.claim(event.sourceSystem(),event.eventCode(),event.eventType(),CONSUMER,event.sourceSystem()+":"+event.eventCode());if(claim==MasterDataEventConsumeLogPort.ClaimResult.ALREADY_SUCCEEDED)return;if(claim==MasterDataEventConsumeLogPort.ClaimResult.IN_PROGRESS)throw new BusinessException(ErrorCode.IDEMPOTENCY_CONFLICT,"退供事件正在处理");payloads.save(event.sourceSystem(),event.eventCode(),CONSUMER,event);try{var context=new CommandContext(0,event.sourceSystem(),0,null,event.eventCode(),null,event.sourceSystem()+":"+event.eventCode(),Set.of());switch(event.eventType()){case "InventoryReturnLocked"->returns.recordInventoryLock(event.returnId(),true,event.referenceNo(),event.lineQuantities(),null,context);case "InventoryReturnLockFailed"->returns.recordInventoryLock(event.returnId(),false,null,event.lineQuantities(),event.reason(),context);case "WmsSupplierReturnOutboundCompleted"->returns.recordOutbound(event.returnId(),event.referenceNo(),event.lineQuantities(),context);case "TmsSupplierReturnWaybillCreated"->returns.recordWaybill(event.returnId(),event.shipmentId(),event.waybillNo(),event.carrierCode(),context);case "TmsSupplierReturnSigned"->returns.recordSigned(event.returnId(),event.lineQuantities(),event.reason(),context);case "TmsSupplierReturnRejected","TmsSupplierReturnTransportException"->returns.recordTransportException(event.returnId(),event.reason(),context);case "BmsSupplierReturnSettlementCompleted"->returns.recordSettlement(event.returnId(),event.referenceNo(),event.offsetAmount(),event.claimAmount(),context);default->throw new BusinessException(ErrorCode.BUSINESS_RULE_FAILED,"不支持的退供事件: "+event.eventType());}inbox.markSucceeded(event.sourceSystem(),event.eventCode(),CONSUMER,false);}catch(RuntimeException exception){inbox.recordFailure(event.sourceSystem(),event.eventCode(),event.eventType(),CONSUMER,event.sourceSystem()+":"+event.eventCode(),exception.getMessage());throw exception;}}}
